import type { Field, Model } from '@prisma/dmmf'

/**
 * Maps a Prisma scalar type name to its TypeScript equivalent.
 * Used both for interface field types and for deriving ID field types in client methods.
 */
function scalarTypeToTs(typeName: string): string {
  switch (typeName) {
    case 'String':
      return 'string'
    case 'Int':
    case 'Float':
      return 'number'
    case 'Boolean':
      return 'boolean'
    case 'DateTime':
      return 'Date'
    case 'BigInt':
      return 'bigint'
    case 'Bytes':
      return 'Uint8Array'
    case 'Json':
      return 'unknown'
    case 'Decimal':
      // Decimal is represented as a string to preserve precision
      return 'string'
    default:
      return typeName
  }
}

/**
 * Converts a DMMF field to its full TypeScript type string, including list
 * (`[]`) and nullability (`| null`) modifiers.
 */
function prismaTypeToTs(field: Field): string {
  let tsType = scalarTypeToTs(field.type)
  if (field.isList) {
    tsType = `${tsType}[]`
  }
  if (!field.isRequired) {
    tsType = `${tsType} | null`
  }
  return tsType
}

/**
 * Renders a TypeScript interface for a Prisma model.
 * Relation fields (kind === 'object') are omitted since they are not part of
 * a flat REST representation.
 */
export function renderInterface(model: Model): string {
  const lines = model.fields
    .filter((f) => f.kind !== 'object')
    .map((f) => {
      const optional = f.isRequired ? '' : '?'
      return `  ${f.name}${optional}: ${prismaTypeToTs(f)}`
    })
  return `export interface ${model.name} {\n${lines.join('\n')}\n}`
}

/**
 * Renders a typed REST client class for a Prisma model with CRUD methods.
 */
export function renderModelClient(model: Model): string {
  const idField = model.fields.find((f) => f.isId)
  const idName = idField?.name ?? 'id'
  const idType = idField ? scalarTypeToTs(idField.type) : 'string'
  const resource = model.name.toLowerCase()
  const name = model.name

  return `export class ${name}RestClient {
  constructor(private readonly baseUrl: string) {}

  async findMany(params?: { where?: Partial<${name}>; take?: number; skip?: number }): Promise<${name}[]> {
    const url = new URL(\`\${this.baseUrl}/${resource}\`)
    if (params?.take !== undefined) url.searchParams.set('take', String(params.take))
    if (params?.skip !== undefined) url.searchParams.set('skip', String(params.skip))
    if (params?.where !== undefined) url.searchParams.set('where', JSON.stringify(params.where))
    const response = await fetch(url.toString())
    return response.json() as Promise<${name}[]>
  }

  async findUnique(params: { where: { ${idName}: ${idType} } }): Promise<${name} | null> {
    const response = await fetch(\`\${this.baseUrl}/${resource}/\${params.where.${idName}}\`)
    if (response.status === 404) return null
    return response.json() as Promise<${name}>
  }

  async create(params: { data: Omit<${name}, '${idName}'> }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}\`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<${name}>
  }

  async update(params: { where: { ${idName}: ${idType} }; data: Partial<${name}> }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}/\${params.where.${idName}}\`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<${name}>
  }

  async delete(params: { where: { ${idName}: ${idType} } }): Promise<${name}> {
    const response = await fetch(\`\${this.baseUrl}/${resource}/\${params.where.${idName}}\`, {
      method: 'DELETE',
    })
    return response.json() as Promise<${name}>
  }
}`
}

/**
 * Renders the complete `rest-client.ts` file content from a list of DMMF models.
 */
export function renderFile(models: readonly Model[]): string {
  const header = `/**
 * Generated by @prisma/generator-rest-client
 * Do not edit this file manually.
 */`

  const interfaces = models.map(renderInterface).join('\n\n')
  const clients = models.map(renderModelClient).join('\n\n')

  return [header, interfaces, clients].join('\n\n') + '\n'
}

