    const response = await fetch(`${this.baseUrl}/user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<User>
  }

  async update(params: { where: { id: number }; data: Partial<User> }): Promise<User> {
    const response = await fetch(`${this.baseUrl}/user/${params.where.id}`, {
      method: 'PATCH',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(params.data),
    })
    return response.json() as Promise<User>
  }

  async delete(params: { where: { id: number } }): Promise<User> {
    const response = await fetch(`${this.baseUrl}/user/${params.where.id}`, {
      method: 'DELETE',
    })
    return response.json() as Promise<User>
  }
}
